            keys[i] = "k";
            values[i] = "v";
        }
        format_metric_point("massive_test", keys, values, count, output);
    }

    free(keys);
    free(values);
    free(output);
    printf("test_massive_label_count 完成 (未崩溃)\n\n");
}

// 6. 测试极长指标名称（缓冲区溢出风险测试）
void test_long_metric_name() {
    printf("运行测试: test_long_metric_name...\n");
