    char* output = (char*)malloc(extra_long + 1024);

    if (long_name && output) {
        format_metric_point(long_name, NULL, NULL, 0, output);
    }

    free(long_name);
    free(output);
    printf("test_long_metric_name 完成 (未崩溃)\n\n");
}

int main() {
    // 设置内存分配失败时不崩溃的简单检查
